mapper.select:
SELECT cu.id, u.user_account, u.username, u.email, u.avater, u.telephone, u.sex, cu.role, cu.position_id, cp.position_name, cp.department_id, cd.department_name, u.sign, u.region, cu.join_date, cu.status FROM company_user cu INNER JOIN user u ON cu.user_id = u.id LEFT JOIN company_position cp ON cu.position_id = cp.id LEFT JOIN company_department cd ON cp.department_id = cd.id WHERE cu.company_id = #{companyId} AND cu.status = 1 AND u.disabled = 0
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.user_account LIKE CONCAT('%', #{keyword}, '%') OR u.telephone LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR u.id LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY cu.role DESC, cu.join_date ASC LIMIT #{offset}, #{pageSize}

SELECT u.id, u.user_account, u.username, u.email, u.avater, u.telephone, u.birthday, u.sex, u.role, u.sign, u.region, u.disabled, u.permission, u.create_date, u.update_date, CASE WHEN cu.user_id IS NOT NULL THEN 1 ELSE 0 END AS checked FROM user u LEFT JOIN company_user cu ON cu.user_id = u.id AND cu.company_id = #{companyId} AND cu.status = 1 WHERE u.disabled = 0 AND u.role != 'system'
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.user_account LIKE CONCAT('%', #{keyword}, '%') OR u.telephone LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR u.id LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY checked DESC, u.create_date DESC LIMIT #{offset}, #{pageSize}
